def predict(triples: list[Triple]) -> str:
    """
    Convert a list of food‑related triples into a single fluent sentence.
    """
    if not triples:
        return ""

    # Group triples by subject to create coherent sentences
    subject_triples = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Track which triples have been used to build relationships
    used_triples = set()
    sentences = []

    # Priority order for predicates to create natural flow
    geo_predicates = {"country", "region", "capital", "currency", "demonym",
                      "ethnicGroup", "language", "officialLanguage", "leader",
                      "leaderTitle", "isPartOf", "foundationPlace"}
    food_predicates = {"ingredient", "mainIngredient", "dishVariation", "course",
                       "servingTemperature", "served", "servingSize"}
    nutrition_predicates = {"carbohydrate", "fat", "protein"}
    bio_predicates = {"division", "family", "order", "genus", "class"}
    other_predicates = {"year", "creator", "creatorOfDish", "alternativeName",
                        "related", "similarDish"}

    for subject, subj_triples in subject_triples.items():
        # Sort predicates by priority for natural sentence structure
        sorted_triples = sorted(subj_triples, key=lambda t: (
            0 if t.predicate in geo_predicates else
            1 if t.predicate in food_predicates else
            2 if t.predicate in nutrition_predicates else
            3 if t.predicate in bio_predicates else
            4 if t.predicate in other_predicates else
            5
        ))

        # Build the main sentence for this subject
        parts = []
        first = True

        for t in sorted_triples:
            s, p, o = t.subject, t.predicate, t.object
            clause = ""

            if p == "country":
                clause = f"{s} is from {o}"
            elif p == "region":
                clause = f"{s} originates from {o}"
            elif p == "mainIngredient":
                clause = f"with {o} as the main ingredient"
            elif p == "ingredient":
                clause = f"containing {o}"
            elif p == "dishVariation":
                clause = f"with variations like {o}"
            elif p == "course":
                clause = f"typically served as a {o}"
            elif p == "servingTemperature" or p == "served":
                clause = f"served {o}"
            elif p == "servingSize":
                clause = f"with a serving size of {o}"
            elif p == "carbohydrate":
                clause = f"containing {o} carbohydrates"
            elif p == "fat":
                clause = f"containing {o} fat"
            elif p == "protein":
                clause = f"containing {o} protein"
            elif p == "division":
                clause = f"belonging to the division {o}"
            elif p == "family":
                clause = f"in the family {o}"
            elif p == "order":
                clause = f"under the order {o}"
            elif p == "genus":
                clause = f"of the genus {o}"
            elif p == "class":
                clause = f"classified as a {o}"
            elif p == "alternativeName":
                clause = f"also known as {o}"
            elif p == "creator" or p == "creatorOfDish":
                clause = f"created by {o}"
            elif p == "year":
                clause = f"introduced in {o}"
            elif p == "related":
                clause = f"related to {o}"
            elif p == "similarDish":
                clause = f"similar to {o}"
            elif p == "isPartOf":
                clause = f"part of {o}"
            elif p == "capital":
                clause = f"where the capital is {o}"
            elif p == "leader":
                clause = f"led by {o}"
            elif p == "currency":
                clause = f"using {o} as currency"
            elif p == "demonym":
                clause = f"with {o}"
            elif p == "ethnicGroup":
                clause = f"home to {o}"
            elif p == "language":
                clause = f"where {o} is spoken"
            elif p == "officialLanguage":
                clause = f"with {o} as the official language"
            elif p == "leaderTitle":
                clause = f"with the leader title {o}"
            elif p == "foundationPlace":
                clause = f"founded in {o}"
            else:
                clause = f"{s} {p} {o}"

            if first:
                parts.append(clause)
                first = False
            else:
                # Connect clauses with commas or "and" for readability
                if len(parts) == 1:
                    parts.append(f", {clause}")
                else:
                    parts.append(f", {clause}")

        sentence = "".join(parts) + "."
        sentences.append(sentence)

    # Join multiple subject sentences
    if len(sentences) == 1:
        return sentences[0]
    else:
        return " ".join(sentences)

# EVOLVE-BLOCK-END

